<?php require_once __DIR__.'/../includes/functions.php'; require_once __DIR__.'/../includes/db.php'; require_admin(); include 'partials/header.php'; include 'partials/sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST' && verify_csrf($_POST['csrf_token']??null)){ $st=db()->prepare('UPDATE admins SET status=? WHERE id=?'); $st->execute([post_value('status')==='active'?'active':'inactive',(int)$_POST['id']]); } $users=db()->query('SELECT id,name,username,email,role,status,created_at FROM admins ORDER BY created_at DESC')->fetchAll(); ?><div class="mb-4 flex justify-between"><h2 class="text-3xl font-black">Admin Users</h2><a class="rounded bg-slate-950 px-4 py-2 font-bold text-white" href="user-create.php">Add Admin</a></div><div class="overflow-auto rounded-2xl bg-white shadow"><table class="min-w-full text-sm"><tr class="bg-slate-950 text-white"><th class="p-3">Name</th><th>Username</th><th>Email</th><th>Role</th><th>Status</th></tr><?php foreach($users as $u):?><tr class="border-t"><td class="p-3"><?=e($u['name'])?></td><td><?=e($u['username'])?></td><td><?=e($u['email'])?></td><td><?=e($u['role'])?></td><td><form method="post"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="id" value="<?=e($u['id'])?>"><select name="status" onchange="this.form.submit()"><option value="active" <?=$u['status']==='active'?'selected':''?>>active</option><option value="inactive" <?=$u['status']==='inactive'?'selected':''?>>inactive</option></select></form></td></tr><?php endforeach;?></table></div><?php include 'partials/footer.php'; ?>
